"from fastapi import APIRouter, Depends, HTTPException from sqlalchemy.ext.asyncio import AsyncSession from app.db.session import get_db from app.api.v1.deps import get_current_user_dependency from app.schemas.user import UserResponse, AccountDeleteResponse router = APIRouter(prefix=\"/users/me\", tags=[\"Управление пользователями\"]) @router.get(response_model=UserResponse, summary=\"Получить текущую информацию пользователя\") async def get_current_user_info(auth: dict = Depends(get_current_user_dependency), db: AsyncSession = Depends(get_db)): user_id = auth.get(\"sub\"); if not user_id: raise HTTPException(status_code=401, detail=\"Не авторизован\") from app.db.models.user import User, UserRepository; result = await db.execute(UserRepository.get_by_id(db, user_id)); user = result.scalar_one_or_none(); if not user: raise HTTPException(status_code=404, detail=\"Пользователь не найден\"); return UserResponse(id=user.id, email=user.email, account_name=user.account_name, profile_photo_url=user.profile_photo_url, is_active=user.is_active, created_at=user.created_at, updated_at=user.updated_at) @router.put(response_model=UserResponse, summary=\"Обновить информацию пользователя\") async def update_current_user(request: UserUpdateRequest, auth: dict = Depends(get_current_user_dependency), db: AsyncSession = Depends(get_db)): user_id = auth.get(\"sub\"); user = await UserRepository.get_by_id(db, user_id); if not user: raise HTTPException(status_code=404, detail=\"Пользователь не найден\"); updated_user = await UserService.update_profile(session=db, user=user, account_name=request.account_name, email=request.email, profile_photo_url=request.profile_photo); return UserResponse(id=updated_user.id, email=updated_user.email, account_name=updated_user.account_name, profile_photo_url=updated_user.profile_photo_url, is_active=updated_user.is_active, created_at=updated_user.created_at, updated_at=updated_user.updated_at) @router.delete(summary=\"Удалить аккаунт\") async def delete_current_user_account(auth: dict = Depends(get_current_user_dependency), db: AsyncSession = Depends(get_db)): user_id = auth.get(\"sub\"); user = await UserRepository.get_by_id(db, user_id); if not user: raise HTTPException(status_code=404, detail=\"Пользователь не найден\"); return AccountDeleteResponse(message=\"Аккаунт успешно удален\")"  
